import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import response from './response.json';

interface Location {
  name: string;
  distance: string;
  availableSpots: number;
  hourlyRate: number;
}

interface ParkingData {
  nearestLocation: Location;
  additionalLocations: Location[];
}

export default function Widget() {
  const data = response.data as ParkingData;
  const meta = response.meta;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: meta.theme === 'dark' ? '#333' : '#fff' }} elevation={2}>
      <CardContent sx={{ p: 2 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" sx={{ color: meta.primaryColor }}>
              Nearest Parking
            </Typography>
            <Typography variant="body2" color="text.secondary">
              {data.nearestLocation.name}
            </Typography>
            <Typography variant="body2" fontWeight={500} sx={{ mt: 1 }}>
              {data.nearestLocation.availableSpots} spots available
            </Typography>
            <Typography variant="caption" color="text.secondary">
              {data.nearestLocation.distance} - ${data.nearestLocation.hourlyRate}/hr
            </Typography>
          </Box>

          <Box>
            <Typography variant="body2" sx={{ mb: 1, color: meta.accentColor }}>
              Additional Locations
            </Typography>
            <Stack direction="row" spacing={0.5}>
              {data.additionalLocations.map((location, index) => (
                <Chip
                  key={index}
                  label={`${location.name} (${location.availableSpots})`}
                  sx={{ fontSize: '11px', px: 1, py: 0.5, bgcolor: '#f0f0f0' }}
                />
              ))}
            </Stack>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
